import { useState, useEffect } from 'react';

const API_BASE = process.env.REACT_APP_API_BASE || 'http://localhost:5050';

export default function CoursePathwayAgent() {
  const [tracks, setTracks] = useState([]);
  const [interest, setInterest] = useState('');
  const [completedIds, setCompletedIds] = useState([]);
  const [plan, setPlan] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Fetch available tracks on mount
  useEffect(() => {
    fetch(`${API_BASE}/api/tracks`)
      .then((res) => res.json())
      .then((data) => {
        setTracks(data.tracks || []);
        if (data.tracks?.length) setInterest(data.tracks[0]);
      })
      .catch(() => setError('Could not reach the agent backend. Is it running?'));
  }, []);

  // Fetch roadmap whenever interest changes
  useEffect(() => {
    if (!interest) return;
    loadRoadmap();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [interest]);

  async function loadRoadmap() {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch(`${API_BASE}/api/roadmap`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ interest, completedIds: [] }),
      });
      if (!res.ok) throw new Error('Request failed');
      const data = await res.json();
      setPlan(data);
      setCompletedIds([]);
    } catch (err) {
      setError('Failed to load roadmap. Check the backend server.');
    } finally {
      setLoading(false);
    }
  }

  async function markComplete(courseId) {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch(`${API_BASE}/api/progress`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          interest,
          completedIds,
          newlyCompletedId: courseId,
        }),
      });
      if (!res.ok) throw new Error('Request failed');
      const data = await res.json();
      setPlan(data);
      setCompletedIds(data.completed);
    } catch (err) {
      setError('Failed to update progress. Check the backend server.');
    } finally {
      setLoading(false);
    }
  }

  return (
    <div style={{ maxWidth: 720, margin: '0 auto', padding: '2rem 1rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ fontSize: 22, fontWeight: 500, marginBottom: 4 }}>Course pathway agent</h1>
      <p style={{ fontSize: 14, color: '#666', marginBottom: 24 }}>
        Powered by IBM Granite on watsonx.ai — the roadmap adapts as you complete courses.
      </p>

      <div style={{ marginBottom: 24 }}>
        <label style={{ fontSize: 13, color: '#666', display: 'block', marginBottom: 6 }}>
          What are you interested in?
        </label>
        <select
          value={interest}
          onChange={(e) => setInterest(e.target.value)}
          style={{ padding: '8px 12px', fontSize: 14, borderRadius: 8, border: '1px solid #ddd', minWidth: 240 }}
        >
          {tracks.map((t) => (
            <option key={t} value={t}>{t}</option>
          ))}
        </select>
      </div>

      {error && (
        <div style={{ background: '#fee', color: '#a33', padding: '10px 14px', borderRadius: 8, marginBottom: 20, fontSize: 13 }}>
          {error}
        </div>
      )}

      {loading && <p style={{ fontSize: 14, color: '#888' }}>Thinking...</p>}

      {plan && !loading && (
        <>
          <div style={{ background: '#f5f5f5', borderRadius: 12, padding: '16px 18px', marginBottom: 24, fontSize: 14, lineHeight: 1.6, color: '#333' }}>
            {plan.guidance}
          </div>

          <h2 style={{ fontSize: 16, fontWeight: 500, marginBottom: 12 }}>Recommended next</h2>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 12 }}>
            {plan.recommended.map((course) => (
              <div
                key={course.id}
                style={{
                  border: '1px solid #e0e0e0',
                  borderRadius: 12,
                  padding: '14px 16px',
                  background: '#fff',
                }}
              >
                <div style={{ fontSize: 11, color: '#999', textTransform: 'uppercase', marginBottom: 4 }}>
                  {course.level}
                </div>
                <div style={{ fontSize: 14, fontWeight: 500, marginBottom: 4 }}>{course.title}</div>
                <div style={{ fontSize: 12, color: '#888', marginBottom: 10 }}>{course.hours}h</div>
                <button
                  onClick={() => markComplete(course.id)}
                  style={{
                    fontSize: 12,
                    padding: '6px 12px',
                    borderRadius: 6,
                    border: '1px solid #ccc',
                    background: '#fafafa',
                    cursor: 'pointer',
                    width: '100%',
                  }}
                >
                  Mark complete
                </button>
              </div>
            ))}
          </div>

          {plan.completed?.length > 0 && (
            <p style={{ fontSize: 12, color: '#999', marginTop: 20 }}>
              {plan.completed.length} course(s) completed on this track.
            </p>
          )}
        </>
      )}
    </div>
  );
}
